+    const fn test_raptorq_config() -> RaptorQConfig {
+        RaptorQConfig {
+            symbol_size: 64,
+            repair_ratio_bps: 2_000,
+            max_object_size: 64 * 1_024,
+            decode_timeout: std::time::Duration::from_secs(5),
