+    fn migration_header(
+        zone_id: &ZoneId,
+        computation_id: ObjectId,
+        lease_id: ObjectId,
+    ) -> ObjectHeader {
+        ObjectHeader {
+            schema: ComputationCheckpoint::schema(),
+            zone_id: zone_id.clone(),
+            created_at: 0,
+            provenance: Provenance::new(zone_id.clone()),
+            refs: vec![computation_id, lease_id],
+            foreign_refs: Vec::new(),
+            ttl_secs: Some(3_600),
+            placement: None,
+        }
+    }
